mapper.select:
SELECT ts, battery_pct FROM d_telemetry_${droneId}
WHERE ts >= #{since}
ORDER BY ts ASC

SELECT ts, rssi FROM d_telemetry_${droneId}
WHERE ts >= #{since}
ORDER BY ts ASC

SELECT ts, link_quality, is_active
FROM l_link_${srcDroneId}_${dstDroneId}
WHERE ts >= #{since}
ORDER BY ts DESC
LIMIT #{limit}
